import type { ComponentProps, ComponentRef } from 'react';
import { Toggle as TogglePrimitive, useToggle, useToggleContext } from '@ark-ui/react/toggle';
import { clsx } from 'clsx';
import { forwardRef } from 'react';
import { normalizeClassName } from '@/lib/moduix/normalizeClassName';
import styles from './Toggle.module.css';

type ToggleVariant = 'default' | 'outline' | 'ghost';
type ToggleSize = 'xs' | 'sm' | 'md' | 'lg' | 'icon-sm' | 'icon-md' | 'icon-lg';

const ToggleRoot = forwardRef<
  ComponentRef<typeof TogglePrimitive.Root>,
  ComponentProps<typeof TogglePrimitive.Root> & {
    variant?: ToggleVariant;
    size?: ToggleSize;
  }
>(function ToggleRoot({ className, variant = 'default', size = 'md', ...props }, ref) {
  return (
    <TogglePrimitive.Root
      ref={ref}
      data-slot="toggle-root"
      data-variant={variant}
      data-size={size}
      className={clsx(styles.root, normalizeClassName(className))}
      {...props}
    />
  );
});

const ToggleIndicator = forwardRef<
  ComponentRef<typeof TogglePrimitive.Indicator>,
  ComponentProps<typeof TogglePrimitive.Indicator>
>(function ToggleIndicator({ className, ...props }, ref) {
  return (
    <TogglePrimitive.Indicator
      ref={ref}
      data-slot="toggle-indicator"
      className={clsx(styles.indicator, normalizeClassName(className))}
      {...props}
    />
  );
});

const ToggleContext = TogglePrimitive.Context;

const Toggle = Object.assign(ToggleRoot, {
  Root: ToggleRoot,
  Indicator: ToggleIndicator,
  Context: ToggleContext,
});

export { Toggle, useToggle, useToggleContext };
export type {
  ToggleContextProps,
  ToggleIndicatorBaseProps,
  ToggleIndicatorProps,
  ToggleRootBaseProps,
  ToggleRootProps,
  UseToggleContext,
  UseToggleProps,
  UseToggleReturn,
} from '@ark-ui/react/toggle';

@layer ui.components {
  .root {
    box-sizing: border-box;
    --toggle-border-color-current: transparent;
    --toggle-bg-current: transparent;
    --toggle-bg-hover-current: var(--toggle-bg-current);
    --toggle-bg-active-current: var(--toggle-bg-hover-current);
    --toggle-bg-pressed-current: var(--toggle-bg-current);
    --toggle-color-current: var(--toggle-color, var(--color-foreground));
    --toggle-color-pressed-current: var(--toggle-color-current);
    --toggle-border-color-pressed-current: var(--toggle-border-color-current);
    display: inline-flex;
    align-items: center;
    justify-content: center;
    gap: var(--toggle-content-gap, var(--spacing-2));
    min-height: var(--toggle-size-md, var(--size-lg));
    margin: 0;
    border-style: solid;
    border-width: var(--toggle-border-width, var(--border-width-sm));
    border-radius: var(--toggle-radius, var(--radius-md));
    padding-block: var(--toggle-padding-y-md, 0.5rem);
    padding-inline: var(--toggle-padding-x-md, 1rem);
    border-color: var(--toggle-border-color-current);
    background-color: var(--toggle-bg-current);
    color: var(--toggle-color-current);
    font: inherit;
    font-size: var(--toggle-font-size, var(--text-sm));
    font-weight: var(--toggle-font-weight, var(--weight-medium));
    line-height: var(--toggle-line-height, var(--line-height-text-sm));
    user-select: none;
    white-space: nowrap;
    cursor: pointer;
    transition:
      background-color var(--toggle-transition, var(--transition-default)),
      border-color var(--toggle-transition, var(--transition-default)),
      color var(--toggle-transition, var(--transition-default)),
      opacity var(--toggle-transition, var(--transition-default));

    &:focus-visible {
      outline: var(--toggle-focus-ring-width, var(--border-width-md)) solid
        var(--toggle-focus-ring-color, var(--color-ring));
      outline-offset: var(--toggle-focus-ring-offset, -1px);
    }

    &[data-disabled],
    &[disabled] {
      opacity: var(--toggle-disabled-opacity, var(--opacity-disabled));
      cursor: default;
      pointer-events: none;
    }

    :where(svg) {
      display: block;
      width: var(--toggle-icon-size, 1rem);
      height: var(--toggle-icon-size, 1rem);
      flex-shrink: 0;
    }

    @media (hover: hover) {
      &:hover {
        background-color: var(--toggle-bg-hover-current);
      }
    }

    &:active {
      background-color: var(--toggle-bg-active-current);
    }

    &[data-state='on'],
    &[data-pressed] {
      border-color: var(--toggle-border-color-pressed-current);
      background-color: var(--toggle-bg-pressed-current);
      color: var(--toggle-color-pressed-current);
    }

    &[data-variant='default'] {
      --toggle-border-color-current: var(--toggle-default-border-color, var(--color-border));
      --toggle-bg-current: var(--toggle-default-bg, var(--color-background));
      --toggle-bg-hover-current: var(--toggle-default-bg-hover, var(--color-accent));
      --toggle-bg-active-current: var(--toggle-default-bg-active, var(--color-accent));
      --toggle-bg-pressed-current: var(--toggle-default-bg-pressed, var(--color-primary));
      --toggle-color-current: var(
        --toggle-default-color,
        var(--toggle-color, var(--color-foreground))
      );
      --toggle-color-pressed-current: var(
        --toggle-default-color-pressed,
        var(--color-primary-foreground)
      );
      --toggle-border-color-pressed-current: var(
        --toggle-default-border-color-pressed,
        var(--color-primary)
      );
    }

    &[data-variant='outline'] {
      --toggle-border-color-current: var(--toggle-outline-border-color, var(--color-border));
      --toggle-bg-current: var(--toggle-outline-bg, var(--color-background));
      --toggle-bg-hover-current: var(--toggle-outline-bg-hover, var(--color-accent));
      --toggle-bg-active-current: var(--toggle-outline-bg-active, var(--color-accent));
      --toggle-bg-pressed-current: var(--toggle-outline-bg-pressed, var(--color-primary));
      --toggle-color-current: var(
        --toggle-outline-color,
        var(--toggle-color, var(--color-foreground))
      );
      --toggle-color-pressed-current: var(
        --toggle-outline-color-pressed,
        var(--color-primary-foreground)
      );
      --toggle-border-color-pressed-current: var(
        --toggle-outline-border-color-pressed,
        var(--color-primary)
      );
    }

    &[data-variant='ghost'] {
      --toggle-border-color-current: var(--toggle-ghost-border-color, transparent);
      --toggle-bg-current: var(--toggle-ghost-bg, transparent);
      --toggle-bg-hover-current: var(--toggle-ghost-bg-hover, var(--color-accent));
      --toggle-bg-active-current: var(--toggle-ghost-bg-active, var(--color-accent));
      --toggle-bg-pressed-current: var(--toggle-ghost-bg-pressed, var(--color-accent));
      --toggle-color-current: var(
        --toggle-ghost-color,
        var(--toggle-color, var(--color-foreground))
      );
      --toggle-color-pressed-current: var(--toggle-ghost-color-pressed, var(--color-foreground));
    }

    &[data-size='xs'] {
      min-height: var(--toggle-size-xs, var(--size-xs));
      padding-block: var(--toggle-padding-y-xs, 0.25rem);
      padding-inline: var(--toggle-padding-x-xs, 0.625rem);
      font-size: var(--toggle-font-size-xs, var(--text-xs));
      line-height: var(--toggle-line-height-xs, var(--line-height-text-xs));
    }

    &[data-size='sm'] {
      min-height: var(--toggle-size-sm, var(--size-sm));
      padding-block: var(--toggle-padding-y-sm, 0.375rem);
      padding-inline: var(--toggle-padding-x-sm, 0.75rem);
    }

    &[data-size='lg'] {
      min-height: var(--toggle-size-lg, var(--size-xl));
      padding-block: var(--toggle-padding-y-lg, 0.625rem);
      padding-inline: var(--toggle-padding-x-lg, 1.25rem);
      font-size: var(--toggle-font-size-lg, var(--text-md));
      line-height: var(--toggle-line-height-lg, var(--line-height-text-md));
    }

    &[data-size='icon-sm'],
    &[data-size='icon-md'],
    &[data-size='icon-lg'] {
      padding: 0;
      gap: 0;
    }

    &[data-size='icon-sm'] {
      width: var(--toggle-size-icon-sm, var(--size-sm));
      height: var(--toggle-size-icon-sm, var(--size-sm));
    }

    &[data-size='icon-md'] {
      width: var(--toggle-size-icon-md, var(--size-lg));
      height: var(--toggle-size-icon-md, var(--size-lg));
    }

    &[data-size='icon-lg'] {
      width: var(--toggle-size-icon-lg, var(--size-xl));
      height: var(--toggle-size-icon-lg, var(--size-xl));
    }
  }

  .indicator {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    color: inherit;
  }
}

export { Toggle, useToggle, useToggleContext } from './Toggle';
export type {
  ToggleContextProps,
  ToggleIndicatorBaseProps,
  ToggleIndicatorProps,
  ToggleRootBaseProps,
  ToggleRootProps,
  UseToggleContext,
  UseToggleProps,
  UseToggleReturn,
} from './Toggle';
